/** 
 * Forward declaration of guess API.
 * @param  num   your guess
 * @return 	     -1 if num is higher than the picked number
 *			      1 if num is lower than the picked number
 *               otherwise return 0
 * int guess(int num);
 */

class Solution {
public:
    int guessNumber(int n) {
        long long st = 1;
        long long end = n;
        int test;
        int gues = 1;
        while(gues){
            test = st + (end-st) /2;
            gues = guess(test);
            if(gues == -1)
                end = test;
            else 
                st = test +1;
        }
        return test;
    }
};

